#include <stdio.h>
#include <string.h>

union Data {
  int i;
  float f;
  char str[20];
};

int main() {
  union Data data;
  data.i = 42;
  printf("Integer: %d\n", data.i);
  data.f = 3.14;
  printf("Float: %.2f\n", data.f);
  // Note: data.i is now overwritten
  printf("Integer after float: %d\n", data.i);
  return 0;
}
